import * as React from 'react';
import MinimalProvider from './providers/minimal/provider';
export { default as MinimalProvider } from './providers/minimal/provider';
import type { IItem } from '../toolbar';
import { SvgIconName } from '../icon-names';

/**
 * @since 0.15
 */
export type ElementVariant = 'primary' | 'danger' | 'success' | 'warning';

/**
 * @since 0.15
 */
export type ButtonProps = {
    type?: "submit" | "reset" | "button";
    icon?: SvgIconName;
    variant?: ElementVariant;
    onClick?: (event: React.MouseEvent<HTMLElement>) => void;
    disabled?: boolean;
    loading?: boolean;
    title?: string;
    minimal?: boolean;
    active?: boolean;
    style?: React.CSSProperties;
    className?: string;
};

/**
 * @since 0.15
 */
export type RadioProps = {
    name?: string;
    label?: string;
    value: string | number;
    checked?: boolean;
    onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
};

/**
 * @since 0.15
 */
export type SliderProps = {
    min?: number;
    max?: number;
    stepSize?: number;
    labelStepSize?: number;
    value?: number;
    onChange?: (value: number) => void;
    disabled?: boolean;
    labelValues?: number[];
};

/**
 * @since 0.15
 */
export type CollapsibleProps = {
    isOpen: boolean;
};

/**
 * @since 0.15
 */
export type CalloutProps = {
    variant?: ElementVariant;
    title?: React.ReactNode;
    icon?: SvgIconName;
};

/**
 * @since 0.15
 */
export type CheckboxProps = {
    checked?: boolean;
    label?: string;
    onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
    disabled?: boolean;
    /** @since 0.15 */
    id?: string;
    /** @since 0.15 */
    name?: string;
};

/**
 * @since 0.15
 */
export type IconProps = {
    icon?: SvgIconName;
    style?: React.CSSProperties;
    iconSize?: number;
};

/**
 * @since 0.15
 */
export type CardProps = {
    style?: React.CSSProperties;
};

/**
 * @since 0.15
 */
export type NumericInputProps = {
    style?: React.CSSProperties;
    min?: number;
    max?: number;
    value?: number;
    disabled?: boolean;
    onChange?: (value: number) => void;
};

/**
 * @since 0.15
 */
export type MenuProps = {};

/**
 * @since 0.15
 */
export type InputGroupProps = {
    style?: React.CSSProperties;
    round?: boolean;
    autoFocus?: boolean;
    leftIcon?: SvgIconName;
    placeholder?: string;
    value?: string;
    readOnly?: boolean;
    /** @since 0.15 */
    disabled?: boolean;
    /** @since 0.15 */
    id?: string;
    /** @since 0.15 */
    name?: string;
    rightElement?: JSX.Element;
    onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
    onClick?: (event: React.MouseEvent<HTMLElement>) => void;
}

/**
 * @since 0.15
 */
export type NonIdealStateProps = {
    icon?: SvgIconName | JSX.Element;
    title?: string | JSX.Element;
    description?: string;
    action?: JSX.Element;
}

/**
 * @since 0.15
 */
export type SpinnerSize = "small" | "standard" | "large";

/**
 * @since 0.15
 */
export type SpinnerProps = {
    variant?: ElementVariant;
    sizePreset?: SpinnerSize;
}

/**
 * @since 0.15
 */
export type SwitchProps = {
    style?: React.CSSProperties;
    disabled?: boolean;
    checked?: boolean;
    label?: string;
    labelElement?: JSX.Element;
    onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
}

/**
 * @since 0.15
 */
export type SelectProps<TValue = string, TAllowPlaceholder extends true | false = true> = {
    id?: string;
    name?: string;
    fill?: boolean;
    style?: React.CSSProperties;
    placeholder?: TAllowPlaceholder extends true ? string : never;
    value?: TAllowPlaceholder extends true ? TValue | undefined : TValue;
    extraClassNames?: string;
    keyFunc?: (item: { value: TValue, label: string }) => React.Key;
    onChange?: (value: TAllowPlaceholder extends true ? TValue | undefined : TValue) => void;
    items: { value: TValue, label: string }[]
}

/**
 * @since 0.15
 */
export type FileInputProps = {
    fill?: boolean;
    text?: string;
    buttonText?: string;
    onInputChange?: React.FormEventHandler<HTMLInputElement>;
}

/**
 * @since 0.15
 */
export type FormGroupProps = {
    label?: React.ReactNode;
    /** @since 0.15 */
    labelFor?: string;
    inline?: boolean;
}

/**
 * @since 0.15
 */
export type EditableTextProps = {
    value?: string;
    onChange?: (value: string) => void;
}

/**
 * @since 0.15
 */
export type MenuComponentProps = {
    items: IItem[];
    onInvoked?: () => void;
}

/**
 * @since 0.15
 */
export interface TabSetProps {
    id?: string;
    activeTabId?: string | number;
    className?: string;
    onTabChanged?: (tabId: string | number) => void;
    tabs: {
        id: string | number,
        title: React.ReactNode,
        content?: JSX.Element
    }[];
}

/**
 * @since 0.15
 */
export type DrawerProps = {
    icon?: SvgIconName;
    onClose?: (event: React.SyntheticEvent<HTMLElement>) => void;
    title?: string;
    position?: Positioning;
    isOpen?: boolean;
}

export type Positioning = "left" | "bottom" | "right" | "top";

/**
 * @since 0.15
 */
export type ToastPosition = "top" | "top-left" | "top-right" | "bottom" | "bottom-left" | "bottom-right";

/**
 * @since 0.15
 */
export type ToastMessage = {
    icon?: SvgIconName;
    message: string | JSX.Element;
    variant?: ElementVariant;
};

/**
 * The imperative API exposed by the abstract Toaster component via a ref.
 *
 * @since 0.15
 */
export interface IToasterRef {
    /**
     * Displays a toast notification and returns its unique key.
     */
    show(message: ToastMessage): string | undefined;
    /**
     * Dismisses the toast notification identified by the given key.
     */
    dismiss(key: string): void;
}

/**
 * @since 0.15
 */
export type ToasterProps = {
    usePortal?: boolean;
    position?: ToastPosition;
};

/**
 * @since 0.15
 */
export type DialogProps = {
    icon?: SvgIconName;
    isOpen?: boolean;
    usePortal?: boolean;
    onClose?: () => void;
    title?: string;
};

/**
 * Props for the outer dialog container wrapper used when composing a custom dialog layout.
 *
 * @since 0.15
 */
export type DialogContainerProps = {
    style?: React.CSSProperties;
    className?: string;
};

/**
 * Props for the dialog shell element (the visible chrome that wraps header and body).
 *
 * @since 0.15
 */
export type DialogShellProps = {
    style?: React.CSSProperties;
    className?: string;
};

/**
 * Props for the dialog header area when composing a custom dialog layout.
 *
 * @since 0.15
 */
export type DialogHeaderProps = {
    className?: string;
};

/**
 * Props for the dialog body area when composing a custom dialog layout.
 *
 * @since 0.15
 */
export type DialogBodyProps = {
    style?: React.CSSProperties;
    className?: string;
};

/**
 * Props for the dialog footer area when composing a custom dialog layout.
 *
 * @since 0.15
 */
export type DialogFooterProps = {
    style?: React.CSSProperties;
    className?: string;
};

/**
 * Props for the dialog footer actions area (button row) when composing a custom dialog layout.
 *
 * @since 0.15
 */
export type DialogFooterActionsProps = {
    style?: React.CSSProperties;
    className?: string;
};

/**
 * @since 0.15
 */
export type PopoverProps = {
    usePortal?: boolean;
    position: Positioning,
    minimal?: boolean;
}

/**
 * @since 0.15
 */
export type HeadingProps = {
    level: 1 | 2 | 3 | 4 | 5 | 6;
    style?: React.CSSProperties;
    className?: string;
};

/**
 * @since 0.15
 */
export type TextProps = {
    component?: "span" | "p" | "div";
    style?: React.CSSProperties;
    className?: string;
}

/**
 * Props for a styled HTML table
 *
 * @since 0.15
 */
export type HtmlTableProps = {
    condensed?: boolean;
    bordered?: boolean;
    className?: string;
    style?: React.CSSProperties;
}

/**
 * Defines a toolkit/design-system agnostic context for requesting UI atoms
 * 
 * The mounted provider determines the underlying toolkit/design-system backing the
 * requested elements.
 * 
 * @since 0.15
 */
export interface IElementContext {
    Text: React.ComponentType<React.PropsWithChildren<TextProps>>;
    Heading: React.ComponentType<React.PropsWithChildren<HeadingProps>>;
    Button: React.ComponentType<React.PropsWithChildren<ButtonProps>>;
    Radio: React.ComponentType<RadioProps>;
    Slider: React.ComponentType<SliderProps>;
    Collapsible: React.ComponentType<React.PropsWithChildren<CollapsibleProps>>;
    Callout: React.ComponentType<React.PropsWithChildren<CalloutProps>>;
    Checkbox: React.ComponentType<CheckboxProps>;
    Icon: React.ComponentType<IconProps>;
    Card: React.ComponentType<React.PropsWithChildren<CardProps>>;
    NumericInput: React.ComponentType<NumericInputProps>;
    InputGroup: React.ComponentType<InputGroupProps>;
    NonIdealState: React.ComponentType<NonIdealStateProps>;
    Spinner: React.ComponentType<SpinnerProps>;
    Switch: React.ComponentType<SwitchProps>;
    Select: React.ComponentType<SelectProps>;
    FileInput: React.ComponentType<FileInputProps>;
    FormGroup: React.ComponentType<React.PropsWithChildren<FormGroupProps>>;
    EditableText: React.ComponentType<EditableTextProps>;
    MenuComponent: React.ComponentType<MenuComponentProps>;
    TabSet: React.ComponentType<TabSetProps>;
    Drawer: React.ComponentType<React.PropsWithChildren<DrawerProps>>;
    Popover: React.ComponentType<React.PropsWithChildren<PopoverProps>>;
    Toaster: React.ForwardRefExoticComponent<ToasterProps & React.RefAttributes<IToasterRef>>;
    Dialog: React.ComponentType<React.PropsWithChildren<DialogProps>>;
    DialogContainer: React.ComponentType<React.PropsWithChildren<DialogContainerProps>>;
    DialogShell: React.ComponentType<React.PropsWithChildren<DialogShellProps>>;
    DialogHeader: React.ComponentType<React.PropsWithChildren<DialogHeaderProps>>;
    DialogBody: React.ComponentType<React.PropsWithChildren<DialogBodyProps>>;
    DialogFooter: React.ComponentType<React.PropsWithChildren<DialogFooterProps>>;
    DialogFooterActions: React.ComponentType<React.PropsWithChildren<DialogFooterActionsProps>>;
    /**
     * A styled HTML table element
     * @since 0.15
     */
    HtmlTable: React.ComponentType<React.PropsWithChildren<HtmlTableProps>>;
}

const ElementContext = React.createContext<IElementContext>(MinimalProvider);

/**
 * Accesses the UI element context
 * 
 * @returns 
 * @since 0.15
 */
export const useElementContext = () => {
    const context = React.useContext(ElementContext);
    return context;
};

/**
 * The UI element provider component. To override the default UI element set, mount
 * this component near the top with a custom UI element provider
 * 
 * @since 0.15
 */
export const ElementProvider = ElementContext.Provider;

/**
 * Provides a type-safe wrapper over the abstract Select UI element
 * 
 * @param props 
 * @returns 
 * @since 0.15
 */
export function TypedSelect<TValue, TAllowPlaceholder extends true | false>(props: SelectProps<TValue, TAllowPlaceholder>) {
    const { id, name, value, onChange, items, fill, placeholder, keyFunc, style } = props;
    const { Select } = useElementContext();
    return <Select id={id}
        name={name}
        value={value as any}
        onChange={onChange as any}
        items={items as any}
        fill={fill}
        style={style}
        placeholder={placeholder}
        keyFunc={keyFunc as any} />
}

/**
 * @since 0.15
 */
export type ElementGroupProps = {
    style?: React.CSSProperties;
    vertical?: boolean;
};

/**
 * A inline flex row wrapper that can form the basis of button groups or toolbars
 * 
 * @param param0 
 * @returns 
 * @since 0.15
 */
export const ElementGroup: React.FC<React.PropsWithChildren<ElementGroupProps>> = ({ style, vertical, children }) => {
    return <div style={style} className={`mrl-element-group ${vertical === true ? 'mrl-element-group-vertical' : 'mrl-element-group-horizontal'}`}>
        {children}
    </div>
}